/**
 * @file Payment and Email Service Configuration
 * @module server/payment-email-config
 *
 * @remarks
 * This module manages configuration for third-party payment processing (Stripe)
 * and email delivery (SendGrid) services. It provides typed interfaces and
 * validation for these external service credentials.
 */

/**
 * Stripe payment service configuration
 *
 * @remarks
 * Configuration for Stripe API integration including secret key for server-side
 * operations, publishable key for client-side usage, and webhook secret for
 * verifying Stripe-initiated events.
 */
export interface StripeConfig {
  /** Stripe secret API key (sk_test_* or sk_live_*) */
  secretKey: string | undefined;
  /** Stripe publishable key (pk_test_* or pk_live_*) */
  publishableKey: string | undefined;
  /** Webhook endpoint secret for verifying webhook signatures (whsec_*) */
  webhookSecret: string | undefined;
  /** Whether this is a production configuration */
  isProduction: boolean;
}

/**
 * SendGrid email service configuration
 *
 * @remarks
 * Configuration for SendGrid transactional email API including API credentials
 * and default sender information for outgoing emails.
 */
export interface SendGridConfig {
  /** SendGrid API key for authentication (SG.*) */
  apiKey: string | undefined;
  /** Default sender email address (must be verified in SendGrid) */
  fromEmail: string | undefined;
  /** Default sender name for display in email clients */
  fromName: string | undefined;
}

/**
 * Combined payment and email service configuration
 */
export interface PaymentEmailConfig {
  /** Stripe service configuration */
  stripe: StripeConfig;
  /** SendGrid service configuration */
  sendgrid: SendGridConfig;
}

/**
 * Loads and normalizes Stripe configuration from environment variables
 *
 * @remarks
 * Environment variables:
 * - STRIPE_SECRET_KEY: Stripe secret API key
 * - STRIPE_PUBLISHABLE_KEY: Stripe publishable key
 * - STRIPE_WEBHOOK_SECRET: Webhook endpoint secret
 * - NODE_ENV: Determines if production configuration
 *
 * @returns Stripe configuration object with loaded values
 */
function loadStripeConfig(): StripeConfig {
  const secretKey = process.env.STRIPE_SECRET_KEY?.trim();
  const publishableKey = process.env.STRIPE_PUBLISHABLE_KEY?.trim();
  const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET?.trim();
  const isProduction = (process.env.NODE_ENV || '').toLowerCase() === 'production';

  return {
    secretKey: secretKey || undefined,
    publishableKey: publishableKey || undefined,
    webhookSecret: webhookSecret || undefined,
    isProduction
  };
}

/**
 * Loads and normalizes SendGrid configuration from environment variables
 *
 * @remarks
 * Environment variables:
 * - SENDGRID_API_KEY: SendGrid API key for authentication
 * - SENDGRID_FROM_EMAIL: Default sender email address
 * - SENDGRID_FROM_NAME: Default sender display name
 *
 * @returns SendGrid configuration object with loaded values
 */
function loadSendGridConfig(): SendGridConfig {
  const apiKey = process.env.SENDGRID_API_KEY?.trim();
  const fromEmail = process.env.SENDGRID_FROM_EMAIL?.trim();
  const fromName = process.env.SENDGRID_FROM_NAME?.trim();

  return {
    apiKey: apiKey || undefined,
    fromEmail: fromEmail || undefined,
    fromName: fromName || undefined
  };
}

/**
 * Validates Stripe configuration for completeness
 *
 * @remarks
 * Checks that all required Stripe credentials are present when Stripe
 * integration is enabled. Returns array of missing required fields.
 *
 * @param config - Stripe configuration to validate
 * @returns Array of missing required fields (empty if valid)
 */
export function validateStripeConfig(config: StripeConfig): string[] {
  const missing: string[] = [];

  // Only validate if any Stripe field is configured
  if (config.secretKey || config.publishableKey || config.webhookSecret) {
    if (!config.secretKey) {
      missing.push('STRIPE_SECRET_KEY');
    }
    if (!config.publishableKey) {
      missing.push('STRIPE_PUBLISHABLE_KEY');
    }
    if (!config.webhookSecret) {
      missing.push('STRIPE_WEBHOOK_SECRET');
    }
  }

  return missing;
}

/**
 * Validates SendGrid configuration for completeness
 *
 * @remarks
 * Checks that all required SendGrid credentials are present when SendGrid
 * integration is enabled. Returns array of missing required fields.
 *
 * @param config - SendGrid configuration to validate
 * @returns Array of missing required fields (empty if valid)
 */
export function validateSendGridConfig(config: SendGridConfig): string[] {
  const missing: string[] = [];

  // Only validate if any SendGrid field is configured
  if (config.apiKey || config.fromEmail || config.fromName) {
    if (!config.apiKey) {
      missing.push('SENDGRID_API_KEY');
    }
    if (!config.fromEmail) {
      missing.push('SENDGRID_FROM_EMAIL');
    }
    if (!config.fromName) {
      missing.push('SENDGRID_FROM_NAME');
    }
  }

  return missing;
}

/**
 * Checks if Stripe integration is enabled
 *
 * @remarks
 * Returns true if at least one Stripe credential is configured.
 *
 * @param config - Stripe configuration
 * @returns True if Stripe is configured
 */
export function isStripeEnabled(config: StripeConfig): boolean {
  return !!(config.secretKey || config.publishableKey || config.webhookSecret);
}

/**
 * Checks if SendGrid integration is enabled
 *
 * @remarks
 * Returns true if at least one SendGrid credential is configured.
 *
 * @param config - SendGrid configuration
 * @returns True if SendGrid is configured
 */
export function isSendGridEnabled(config: SendGridConfig): boolean {
  return !!(config.apiKey || config.fromEmail || config.fromName);
}

/**
 * Loads and validates all payment and email service configurations
 *
 * @remarks
 * Creates configuration objects and validates that if any service is
 * partially configured, all required fields are present. Logs warnings
 * for incomplete configurations.
 *
 * @returns Complete payment and email configuration object
 */
export function loadPaymentEmailConfig(): PaymentEmailConfig {
  const stripe = loadStripeConfig();
  const sendgrid = loadSendGridConfig();

  // Validate completeness of configured services
  const stripeErrors = validateStripeConfig(stripe);
  const sendgridErrors = validateSendGridConfig(sendgrid);

  if (stripeErrors.length > 0) {
    console.warn(
      `[CONFIG] Stripe partially configured. Missing required fields: ${stripeErrors.join(', ')}`
    );
  }

  if (sendgridErrors.length > 0) {
    console.warn(
      `[CONFIG] SendGrid partially configured. Missing required fields: ${sendgridErrors.join(', ')}`
    );
  }

  return {
    stripe,
    sendgrid
  };
}

/**
 * Singleton instance of payment and email service configuration
 *
 * @remarks
 * Loaded once at module import time. Access via this export rather than
 * calling loadPaymentEmailConfig() multiple times.
 */
export const PAYMENT_EMAIL_CONFIG = loadPaymentEmailConfig();

export default PAYMENT_EMAIL_CONFIG;

